require "prefabutil" local G = DYCLegendary local dlc = G.dlc local lootSystem = G.lootSystem local assets = { } local function DYCGem(name) local fn = function() local Sparkle = function(inst) local floatable = inst.components.floatable if floatable then floatable:UpdateAnimations( "idle_water_sparkle" , "idle_sparkle" ) end if floatable and floatable.onwater then inst.AnimState:PushAnimation( "idle_water" ) else inst.AnimState:PushAnimation( "idle" ) end inst.sparkletask = inst:DoTaskInTime(0x4 + math.random(), inst.sparklefn) end local StartSparkling = function(inst) inst.sparkletask = inst:DoTaskInTime(0x1, inst.sparklefn) end local StopSparkling = function(inst) if inst.sparkletask then inst.sparkletask:Cancel() inst.sparkletask = nil end end local inst = CreateEntity() inst.entity:AddTransform() inst.entity:AddAnimState() inst.entity:AddSoundEmitter() inst.AnimState:SetBank( "dyc_gems" ) inst.AnimState:SetBuild( "dyc_gem_"..name) inst.AnimState:PlayAnimation( "idle" ) MakeInventoryPhysics(inst) if dlc >= 0x2 then MakeInventoryFloatable(inst, "idle_water" , "idle" ) end inst:AddComponent( "inspectable" ) inst:AddComponent( "inventoryitem" ) inst.components.inventoryitem.atlasname = "images/inventoryimages/dyc_gem_"..name..".xml" inst.components.inventoryitem.imagename = "dyc_gem_"..name inst.sparklefn = Sparkle StartSparkling(inst) if name == "blue" then inst:AddComponent( "equippable" ) inst:AddEnchantment( "bluegem" ) inst:SetRandomQuality() elseif name == "purple" then inst:AddComponent( "equippable" ) inst:AddEnchantment( "purplegem" ) inst:SetRandomQuality() elseif name == "orange" then inst:AddComponent( "equippable" ) inst:AddEnchantment( "orangegem" ) inst:SetRandomQuality() elseif name == "enc" then inst:AddComponent( "stackable" ) inst.components.stackable.maxsize = 0x63 inst:AddComponent( "repairer" ) inst.components.repairer.repairmaterial = "gem" inst.components.repairer.userepairvalue = 0x64 inst.components.inventoryitem:SetEnchanter({ time = 0x4, canEnchantFn = function(enchanterInst, object) return object:GetEnchantmentCount(nil, { "noscrap" , "legendary" }) < 0x3 end, enchantFn = function(enchanterInst, object) local enc = nil for i = 0x1, 0x1e do enc = object:AddEnchantment(lootSystem:GetEnchantmentByLevel(object, 0x1), true) if enc ~= nil then return true end end return false end,}) elseif name == "enc5" then inst:AddComponent( "stackable" ) inst.components.stackable.maxsize = 0x63 inst:AddComponent( "repairer" ) inst.components.repairer.repairmaterial = "gem" inst.components.repairer.userepairvalue = 0x78 inst.components.inventoryitem:SetEnchanter({time = 0x5, canEnchantFn = function(enchanterInst, object) return object:GetEnchantmentCount(nil, { "noscrap" , "legendary" }) < 0x4 end, enchantFn = function(enchanterInst, object) local lv = math.random() < 0.22 and 0x3 or 0x2 local enc = nil for i = 0x1, 0x1e do enc = object:AddEnchantment(lootSystem:GetEnchantmentByLevel(object, lv), true) if enc ~= nil then return true end end return false end,}) elseif name == "enc2" then inst:AddComponent( "repairer" ) inst.components.repairer.repairmaterial = "gem" inst.components.repairer.userepairvalue = 0x78 inst.components.inventoryitem:SetEnchanter({time = 0x6, canEnchantFn = function(enchanterInst, object) return object:GetEnchantmentCount(nil, { "noscrap" , "legendary" }) < 0x4 end,}) elseif name == "enc3" then inst:AddComponent( "stackable" ) inst.components.stackable.maxsize = 0x63 inst.components.inventoryitem:SetEnchanter({time = 0x2, canEnchantFn = function(enchanterInst, object) return object:GetEnchantmentCount(nil, { "noscrap" , "legendary" }) > 0x0 end, enchantFn = function(enchanterInst, object) local enc = object:GetRandomEnchantment(nil, { "noscrap" , "legendary" }) if enc then object:RemoveEnchantment(enc) return true end return false end,}) elseif name == "enc4" then inst:AddComponent( "stackable" ) inst.components.stackable.maxsize = 0x63 inst.components.inventoryitem:SetEnchanter({time = 0x2, enchantFn = function(enchanterInst, object) object:SetRandomQuality(0.65, 1.35) return true end,}) end if inst.components.equippable then inst.components.equippable.equipslot = EQUIPSLOTS.AMULET or EQUIPSLOTS.NECK or EQUIPSLOTS.NECKLACE or EQUIPSLOTS.BODY end return inst end return fn end local gems = { "blue" , "purple" , "orange" , "enc" , "enc2" , "enc3" , "enc4" , "enc5" } local gemPrefabs = {} for _, name in pairs(gems) do table.insert(assets, Asset( "ATLAS" , "images/inventoryimages/dyc_gem_"..name..".xml" )) table.insert(assets, Asset( "IMAGE" , "images/inventoryimages/dyc_gem_"..name..".tex" )) table.insert(assets, Asset( "ANIM" , "anim/dyc_gem_"..name..".zip" )) table.insert(gemPrefabs, Prefab( "common/inventory/dyc_gem_"..name, DYCGem(name), assets)) end return unpack(gemPrefabs) 